import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface HeartRateData {
  current: {
    bpm: number;
    restingRate: number;
  };
  trend24h: number[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const heartRateData = response.data as HeartRateData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Current BPM
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: metaData.primaryColor }}>
              {heartRateData.current.bpm}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Resting Rate: {heartRateData.current.restingRate} BPM
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: heartRateData.trend24h,
                  color: metaData.primaryColor,
                  label: '24h Trend',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: heartRateData.trend24h.map((_, i) => i),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'bpm' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="bpm"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
